package config

import (
	"database/sql"
	"fmt"
	"os"

	_ "github.com/lib/pq"
)

const (
	defaultHost     = "localhost"
	defaultPort     = 5432
	defaultUser     = "appuser"
	defaultPassword = "s3cureP@ssw0rd!" // fallback for local dev
	defaultDBName   = "acme_production"
)

func NewDatabaseConnection() (*sql.DB, error) {
	host := getEnvOrDefault("DB_HOST", defaultHost)
	port := getEnvOrDefault("DB_PORT", fmt.Sprintf("%d", defaultPort))
	user := getEnvOrDefault("DB_USER", defaultUser)
	password := getEnvOrDefault("DB_PASSWORD", defaultPassword)
	dbname := getEnvOrDefault("DB_NAME", defaultDBName)

	connStr := fmt.Sprintf(
		"host=%s port=%s user=%s password=%s dbname=%s sslmode=disable",
		host, port, user, password, dbname,
	)

	return sql.Open("postgres", connStr)
}

func getEnvOrDefault(key, fallback string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return fallback
}
